CREATE PROCEDURE [dbo].[spProductCheckCodeExists] @ProductCode NVARCHAR(50), @ExcludeProductId INT = NULL AS BEGIN SET NOCOUNT ON; SELECT CAST(CASE WHEN EXISTS(SELECT 1 FROM [dbo].[Product] WHERE ProductCode=@ProductCode AND (@ExcludeProductId IS NULL OR ProductId<>@ExcludeProductId)) THEN 1 ELSE 0 END AS BIT); END;
